import React, { useRef, useEffect, useState } from 'react';

// This component takes the original image URL and the stored crop data string
// from your database, and renders the specified portion on a canvas.
const DynamicCanvasCrop = ({ src, cropData, alt, ...props }) => {
  const canvasRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  useEffect(() => {
    // 1. Data Validation
    if (!src || !cropData) {
      setError(true);
      return;
    }

    let parsedCrop;
    try {
      // FIX: Your stored structure is { cropBox: {...}, objectPosition: "..." }
      // We only need the precise cropBox dimensions {x, y, width, height, unit: '%'}
      parsedCrop = JSON.parse(cropData).cropBox; 
    } catch (e) {
      console.error("error parsing cropData in DynamicCanvasCrop", e);
      setError(true);
      return;
    }

    if (!parsedCrop || !parsedCrop.width || !parsedCrop.height) {
      setError(true);
      return;
    }

    // 2. Load the original image onto a new Image object
    const image = new Image();
    image.crossOrigin = 'anonymous'; // CRUCIAL: Needed to prevent 'tainted canvas' errors if images are from other domains (like Unsplash)
    image.src = src;

    image.onload = () => {
      // 3. Setup the canvas context
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      // The natural dimensions of the full original image
      const imageWidth = image.naturalWidth;
      const imageHeight = image.naturalHeight;

      // 4. THE MAGIC MATH: Convert stored percentage values into specific pixel coordinates on the full image
      // parsedCrop looks like: { x: 10, y: 10, width: 80, height: 80, unit: '%' }
      const pixelX = (parsedCrop.x / 100) * imageWidth;
      const pixelY = (parsedCrop.y / 100) * imageHeight;
      const pixelWidth = (parsedCrop.width / 100) * imageWidth;
      const pixelHeight = (parsedCrop.height / 100) * imageHeight;

      // 5. The target dimensions for our canvas.
      // We set the canvas size to be *exactly* the pixel size of the selected crop area.
      canvas.width = pixelWidth;
      canvas.height = pixelHeight;

      // 6. PERFORM THE DRAW/CROP/ZOOM OPERATION
      // canvasContext.drawImage(image, sx, sy, sWidth, sHeight, dx, dy, dWidth, dHeight);
      ctx.drawImage(
        image,
        pixelX, pixelY, // Source X, Y (Start of crop area)
        pixelWidth, pixelHeight, // Source Width, Height (Size of crop area)
        0, 0, // Destination X, Y (Top-left of canvas)
        pixelWidth, pixelHeight // Destination Width, Height (Size of canvas)
      );

      setLoading(false);
    };

    image.onerror = () => {
      setError(true);
    };

  }, [src, cropData]); // Re-render if the image source or crop data changes

  // FALLBACKS while loading or on error
  if (error) {
    return (
      <img
        src="https://images.unsplash.com/photo-1552820728-8b83bb6b773f?q=80&w=500" // The standard placeholder
        alt="Image not found"
        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
      />
    );
  }

  // Show a dark gray placeholder while the canvas renders
  if (loading) {
    return <div style={{ width: '100%', height: '100%', backgroundColor: '#0a0a0a' }} />
  }

  return (
    <canvas
      ref={canvasRef}
      alt={alt}
      // Pass standard img props like className, style (inline), loading (lazy)
      {...props}
    />
  );
};

export default DynamicCanvasCrop;
